import React from 'react';
import { BrowserRouter as Router, Link, Route, Switch, Redirect, useLocation } from 'react-router-dom';
import { MENU_ITEMS } from '../../config/menu';
import Dashboard from '../../pages/dashboard';
import Customers from '../../pages/customers';
import Orders from '../../pages/orders';
import Technicians from '../../pages/technicians';
import Network from '../../pages/network';
import Billing from '../../pages/billing';
import Plans from '../../pages/plans';
import Stock from '../../pages/stock';
import Reports from '../../pages/reports';
import Permissions from '../../pages/permissions';
import Users from '../../pages/users';
import Integrations from '../../pages/integrations';

const SideMenu: React.FC = () => {
    const location = useLocation();

    return (
        <nav>
            <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'grid', gap: '0.5rem' }}>
                {MENU_ITEMS.map((item) => {
                    const isActive = location.pathname === item.path;

                    return (
                        <li key={item.key}>
                            <Link
                                style={{
                                    display: 'block',
                                    color: isActive ? '#0f172a' : '#cbd5e1',
                                    background: isActive ? '#e2e8f0' : 'transparent',
                                    borderRadius: 6,
                                    padding: '0.4rem 0.55rem',
                                    textDecoration: 'none',
                                    fontWeight: isActive ? 700 : 500,
                                }}
                                to={item.path}
                                title={item.permission}
                            >
                                {item.label}
                            </Link>
                        </li>
                    );
                })}
            </ul>
        </nav>
    );
};

const Layout: React.FC = () => {
    return (
        <Router>
            <div style={{ display: 'flex', minHeight: '100vh', fontFamily: 'Segoe UI, sans-serif' }}>
                <aside style={{ width: '240px', background: '#0f172a', color: '#e2e8f0', padding: '1rem' }}>
                    <h2 style={{ marginTop: 0, color: '#fff' }}>ISP Admin</h2>
                    <p style={{ fontSize: '0.85rem', opacity: 0.85 }}>Painel administrativo</p>
                    <SideMenu />
                </aside>

                <main style={{ flex: 1, background: '#f8fafc' }}>
                    <header style={{ borderBottom: '1px solid #e2e8f0', padding: '0.9rem 1.2rem', background: '#fff' }}>
                        <strong>Provedor ISP 2.0</strong>
                    </header>

                    <Switch>
                        <Route exact path="/">
                            <Redirect to="/dashboard" />
                        </Route>
                        <Route path="/dashboard" component={Dashboard} />
                        <Route path="/customers" component={Customers} />
                        <Route path="/orders" component={Orders} />
                        <Route path="/technicians" component={Technicians} />
                        <Route path="/network" component={Network} />
                        <Route path="/billing" component={Billing} />
                        <Route path="/plans" component={Plans} />
                        <Route path="/stock" component={Stock} />
                        <Route path="/reports" component={Reports} />
                        <Route path="/permissions" component={Permissions} />
                        <Route path="/users" component={Users} />
                        <Route path="/integrations" component={Integrations} />
                    </Switch>
                </main>
            </div>
        </Router>
    );
};

export default Layout;
